function filtrarTabelaInventario() {
    const termo = document.getElementById('filtro-inventario').value.toUpperCase();
    const filtrados = window.itensAtuaisSetor.filter(i => 
        i.nome_produto.toUpperCase().includes(termo) || 
        (i.numero_serie && i.numero_serie.toUpperCase().includes(termo))
    );
    renderizarTabela(filtrados);
}

function gerarExcelInventario(nomeSetor) {
    const dadosParaExcel = window.itensAtuaisSetor.map(i => ({
        'Produto': i.nome_produto,
        'Série/Plaqueta': i.numero_serie || 'N/A',
        'Estado': i.estado,
        'Nota Fiscal': i.nota_fiscal || 'N/A'
    }));

    const ws = XLSX.utils.json_to_sheet(dadosParaExcel);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Inventário");
    XLSX.writeFile(wb, `Inventario_${nomeSetor}.xlsx`);
}

function exportarPDFInventario() {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF('l', 'mm', 'a4'); // 'l' para modo paisagem (landscape)
    const dados = window.dadosInventario;

    doc.setFontSize(16);
    doc.text("INVENTÁRIO GERAL DE BENS E CONSUMÍVEIS - SEMED", 14, 15);
    doc.setFontSize(10);
    doc.text(`Data do Levantamento: ${new Date().toLocaleString()}`, 14, 22);

    const colunas = ["LOCAL / UNIDADE", "PRODUTO", "TIPO", "QTD", "DETALHES/PLAQUETAS"];
    const linhas = dados.map(d => [
        d.local_nome,
        d.produto,
        d.tipo,
        d.quantidade,
        d.detalhes
    ]);

    doc.autoTable({
        head: [colunas],
        body: linhas,
        startY: 30,
        theme: 'striped',
        styles: { fontSize: 8 },
        columnStyles: {
            4: { cellWidth: 80 } // Coluna de detalhes mais larga
        },
        headStyles: { fillStyle: [52, 73, 94] }
    });

    doc.save(`inventario_atual_${new Date().toISOString().split('T')[0]}.pdf`);
}

