async function carregarSetoresParaConsulta() {
    const container = document.getElementById('lista-setores-inventario');
    
    try {
        const res = await fetch(`${API_URL}/patrimonio/setores/meus`, {
            headers: { 'Authorization': `Bearer ${TOKEN}` }
        });
        const setores = await res.json();

        if (Array.isArray(setores) && setores.length > 0) {
            container.innerHTML = setores.map(s => `
                <div class="item-setor-clicavel" onclick="carregarItensPorSetor(${s.id}, '${s.nome}')" 
                     style="padding: 12px; margin-bottom: 8px; background: rgba(255,255,255,0.05); border-radius: 8px; cursor: pointer; transition: 0.3s;">
                    🔹 ${s.nome}
                </div>
            `).join('');
        } else {
            container.innerHTML = '<p style="color:gray; font-size:0.8rem;">Nenhum setor cadastrado.</p>';
        }
    } catch (err) {
        container.innerHTML = '<p style="color:red;">Erro ao carregar.</p>';
    }
}

async function carregarItensPorSetor(setor_id, nome_setor) {
    const cabecalho = document.getElementById('cabecalho-itens');
    const areaTabela = document.getElementById('area-tabela-itens');
    const titulo = document.getElementById('nome-setor-titulo');

    // Destacar o setor selecionado
    document.querySelectorAll('.item-setor-clicavel').forEach(el => el.classList.remove('setor-ativo'));
    event.currentTarget.classList.add('setor-ativo');

    cabecalho.style.visibility = 'visible';
    titulo.innerText = `BENS: ${nome_setor}`;
    
    // Injeta a Barra de Pesquisa e os Botões de Exportação/Partilha
    areaTabela.innerHTML = `
        <div style="display: flex; gap: 10px; margin-bottom: 20px; align-items: center;">
            <input type="text" id="filtro-inventario" onkeyup="filtrarTabelaInventario()" 
                   placeholder="🔍 Pesquisar por nome ou Nº Patrimônio..." class="input-vidro" style="flex: 1;">
            
            <button onclick="gerarExcelInventario('${nome_setor}')" class="btn-sair-vidro" style="background: #16a34a; border:none; color:white;" title="Exportar para Excel">
                Excel 📊
            </button>
            
            <button onclick="partilharInventario('${nome_setor}')" class="btn-sair-vidro" style="background: #7c3aed; border:none; color:white;" title="Partilhar">
                Partilhar 🔗
            </button>
        </div>
        <div id="corpo-tabela-dinamica"><div class="spinner"></div></div>
    `;

    try {
        const res = await fetch(`${API_URL}/patrimonio/meu-inventario?setor_id=${setor_id}`, {
            headers: { 'Authorization': `Bearer ${TOKEN}` }
        });
        const itens = await res.json();
        window.itensAtuaisSetor = itens; // Guarda para exportação

        renderizarTabela(itens);
    } catch (err) {
        document.getElementById('corpo-tabela-dinamica').innerHTML = '<p style="color:red;">Erro ao carregar.</p>';
    }
}

async function partilharInventario(nomeSetor) {
    const texto = `📋 *Inventário SEMED*\nSetor: ${nomeSetor}\nTotal de itens: ${window.itensAtuaisSetor.length}\nGerado em: ${new Date().toLocaleDateString()}`;
    
    // Tenta usar a partilha nativa do telemóvel/browser
    if (navigator.share) {
        try {
            await navigator.share({
                title: 'Inventário de Património',
                text: texto,
                url: window.location.href
            });
        } catch (err) { console.log("Partilha cancelada"); }
    } else {
        // Fallback para WhatsApp Web se não houver partilha nativa
        const urlWhatsapp = `https://api.whatsapp.com/send?text=${encodeURIComponent(texto)}`;
        window.open(urlWhatsapp, '_blank');
    }
}

function renderizarTabela(dados) {
    const container = document.getElementById('corpo-tabela-dinamica');
    
    if (!container) return;

    if (dados.length === 0) {
        container.innerHTML = '<p style="text-align:center; color:gray; margin-top:30px; font-size:0.8rem;">Nenhum bem encontrado neste setor.</p>';
        return;
    }

    // LEGENDA ATUALIZADA: Agora reflete a distinção pelo campo PATRIMÔNIO (RGP)
    const legendaHtml = `
        <div style="display: flex; gap: 20px; margin-bottom: 15px; padding: 10px; background: rgba(0, 0, 0, 0.2); border-radius: 8px; flex-wrap: wrap; border: 1px solid rgba(255,255,255,0.05);">
            <div style="display:flex; align-items:center; gap:8px; font-size:0.75rem; color:#4ade80; font-weight:bold;">
                <span style="font-size: 1.2rem;">●</span> COM Nº PATRIMÔNIO
            </div>
            <div style="display:flex; align-items:center; gap:8px; font-size:0.75rem; color:#fbbf24; font-weight:bold;">
                <span style="font-size: 1.2rem;">●</span> PENDENTE DE ETIQUETA
            </div>
        </div>
    `;

    container.innerHTML = legendaHtml + `
        <div style="overflow-x: auto; border-radius: 10px; background: rgba(0,0,0,0.2);">
            <table style="width:100%; border-collapse: collapse; font-size: 0.82rem; color: white;">
                <thead>
                    <tr style="text-align:left; border-bottom: 2px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.02);">
                        <th style="padding:10px 12px; width: 50px;">ID</th>
                        <th style="padding:10px 12px;">DESCRIÇÃO DO BEM</th>
                        <th style="padding:10px 12px;">Nº PATRIMÔNIO</th>
                        <th style="padding:10px 12px; color: #60a5fa;">Nº RGP</th>
                        <th style="padding:10px 12px;">ESTADO</th>
                        <th style="padding:10px 12px;">NF / CE</th>
                        <th style="padding:10px 12px;">CADASTRO</th>
                        <th style="padding:10px 12px; text-align:center;">VER</th>
                    </tr>
                </thead>
                <tbody>
                    ${dados.map((i, index) => {
                        // --- ALTERAÇÃO SOLICITADA: Verificação baseada no campo 'patrimonio' ---
                        const temPatrimonio = i.patrimonio && String(i.patrimonio).trim() !== '';
                        const emTransito = i.em_transito === true; 

                        // Lógica de Cores da Linha
                        let corTexto = '#fbbf24'; // AMARELO: Padrão (Sem Patrimônio)
                        
                        if (temPatrimonio) {
                            corTexto = '#4ade80'; // VERDE: Se tiver o campo patrimônio preenchido
                        }

                        const coresEstado = { 'BOM': '#4ade80', 'RUIM': '#fbbf24', 'PÉSSIMO': '#ef4444' };
                        const corPonto = coresEstado[i.estado] || '#ffffff';

                        return `
                            <tr onclick="${emTransito ? '' : `selecionarItemParaTransferencia(this, ${i.id}, ${i.setor_id})`}" 
                                style="border-bottom: 1px solid rgba(255,255,255,0.03); color: ${corTexto}; cursor: ${emTransito ? 'not-allowed' : 'pointer'}; transition: 0.2s; opacity: ${emTransito ? '0.4' : '1'};"
                                onmouseover="${emTransito ? '' : "this.style.background='rgba(255,255,255,0.05)'"}" 
                                onmouseout="this.style.background='transparent'"
                                class="linha-inventario-selecionavel">
                                
                                <td style="padding:6px 12px; opacity:0.5; font-size:0.75rem;">#${i.id}</td>
                                
                                <td style="padding:6px 12px; font-weight:600; text-transform: uppercase;"> 
                                    ${i.produto_nome || 'PRODUTO NÃO IDENTIFICADO'}
                                    ${emTransito ? '<br><span style="font-size:0.6rem; color:#fbbf24; font-weight:bold;">[ EM TRÂNSITO ]</span>' : ''}
                                </td>
                                
                                <td style="padding:6px 12px; font-family: 'Courier New', monospace; opacity: 0.8;">
                                    ${i.numero_serie || '<span style="opacity:0.2;">---------</span>'}
                                </td>

                                <td style="padding:6px 12px; font-weight: bold; color: ${corTexto};">
                                    ${i.patrimonio || '<span style="opacity:0.3;"> </span>'}
                                </td>
                                
                                <td style="padding:6px 12px;">
                                    <span style="display:inline-flex; align-items:center; gap:5px; background:rgba(0,0,0,0.3); padding:2px 8px; border-radius:12px; font-size:0.7rem; color:${corPonto}; border: 1px solid ${corPonto}44;">
                                        ● ${i.estado}
                                    </span>
                                </td>
                                
                                <td style="padding:6px 12px; opacity:0.8;">
                                    ${i.nota_fiscal || '<span style="opacity:0.3;">---</span>'}
                                </td>

                                <td style="padding:6px 12px; font-size:0.75rem; opacity:0.6;">
                                    ${i.data_atualizacao ? new Date(i.data_atualizacao).toLocaleDateString('pt-BR') : '---'}
                                </td>
                                
                                <td style="padding:6px 12px; text-align:center;">
                                    <button onclick="event.stopPropagation(); detalharPatrimonio(${i.id})" style="background:none; border:none; cursor:pointer; font-size:1rem; opacity:0.7;"
                                        title="Ver Detalhes">👁️</button>
                                </td>
                            </tr>
                        `;
                    }).join('')}
                </tbody>
            </table>
        </div>
    `;
}

window.detalharPatrimonio = async function(id) {
    if (!id) return;

    try {
        const res = await fetch(`${API_URL}/patrimonio/detalhes/${id}`, {
            headers: { 'Authorization': `Bearer ${TOKEN}` }
        });
        
        // Verifica se a resposta é realmente um JSON antes de tentar ler
        const contentType = res.headers.get("content-type");
        if (!res.ok || !contentType || !contentType.includes("application/json")) {
            console.error("O servidor não retornou um JSON válido. Verifique a rota no backend.");
            return notificar("Erro ao carregar detalhes: Rota não encontrada ou erro no servidor.");
        }

        const item = await res.json();

        // MANTENDO A SUA INTERFACE LINDA (Apenas injetando os dados)
        const modal = document.createElement('div');
        modal.id = 'modal-detalhes-patrimonio';
        modal.className = 'alerta-vidro-overlay';

        const urlAnexo = item.url_nota_fiscal ? `${API_URL}/uploads/notas_fiscais/${item.url_nota_fiscal}` : null;

        modal.innerHTML = `
            <div class="painel-vidro" style="width: 700px; padding: 30px; border: 1px solid rgba(255,255,255,0.2);">
                <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 25px;">
                    <h2 style="color:white; margin:0;">🔍 Detalhes: ${item.nome_produto}</h2>
                    <button onclick="document.getElementById('modal-detalhes-patrimonio').remove()" class="btn-sair-vidro">FECHAR</button>
                </div>
                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 30px; color: white;">
                    <div>
                        <p><small style="color:#60a5fa;">SETOR:</small><br><strong>${item.nome_setor}</strong></p>
                        <p><small style="color:#60a5fa;">Nº PATRIMÔNIO:</small><br><strong>${item.numero_serie || '---'}</strong></p>
                        <p><small style="color:#60a5fa;">Nº RGP:</small><br><strong>${item.patrimonio || '---'}</strong></p>
                        <p><small style="color:#60a5fa;">NOTA FISCAL:</small><br><strong>${item.nota_fiscal || '---'}</strong></p>
                        <p><small style="color:#60a5fa;">ESTADO:</small><br><strong style="color:${item.estado === 'BOM' ? '#4ade80' : '#f87171'}">${item.estado}</strong></p>
                    </div>
                    <div style="background: rgba(255,255,255,0.05); border-radius: 12px; padding: 20px; text-align: center; border: 1px dashed rgba(255,255,255,0.2);">
                        ${urlAnexo ? `
                            <div style="font-size: 3rem;">📄</div>
                            <p style="font-size: 0.8rem; margin-bottom: 15px;">Nota Fiscal anexada.</p>
                            <a href="${urlAnexo}" target="_blank" class="btn-sair-vidro" style="text-decoration:none; display:inline-block; background:#3b82f6;">VER NOTA FISCAL</a>
                        ` : `<div style="opacity: 0.3; font-size: 3rem;">📂</div><p style="color:#888;">Sem anexo.</p>`}
                    </div>
                </div>
            </div>
        `;
        document.body.appendChild(modal);

    } catch (err) {
        console.error("Erro no fetch:", err);
    }
};

function gerarRelatorioPDF(nomeSetor) {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();
    const escola = localStorage.getItem('nome') || 'UNIDADE SEMED';

    // Cabeçalho do PDF
    doc.setFontSize(16);
    doc.text("RELATÓRIO DE INVENTÁRIO PATRIMONIAL", 105, 15, { align: "center" });
    doc.setFontSize(10);
    doc.text(`Unidade: ${escola}`, 14, 25);
    doc.text(`Setor: ${nomeSetor}`, 14, 30);
    doc.text(`Gerado em: ${new Date().toLocaleString('pt-BR')}`, 14, 35);

    doc.autoTable({
        html: '#tabela-inventario-dados',
        startY: 40,
        theme: 'striped',
        headStyles: { fillColor: [30, 58, 138] },
        columns: [
            { header: 'DESCRIÇÃO', dataKey: '0' },
            { header: 'PATRIMÔNIO', dataKey: '1' },
            { header: 'ESTADO', dataKey: '2' }
        ]
    });

    const finalY = doc.lastAutoTable.finalY + 30;
    doc.line(60, finalY, 150, finalY);
    doc.text("Assinatura do Responsável pelo Setor", 105, finalY + 5, { align: "center" });

    doc.save(`Inventario_${nomeSetor}.pdf`);
}

// 2. Função para Gerar o PDF (Usando jsPDF e AutoTable)
function gerarPDFInventario(nomeSetor) {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();
    const dataAtual = new Date().toLocaleString('pt-BR');

    // Título do Relatório
    doc.setFontSize(18);
    doc.text("Relatório de Inventário de Patrimônio", 14, 20);
    
    doc.setFontSize(11);
    doc.text(`Setor: ${nomeSetor}`, 14, 30);
    doc.text(`Data de Emissão: ${dataAtual}`, 14, 36);
    doc.text(`Unidade: ${localStorage.getItem('nome_unidade') || 'Sua Unidade'}`, 14, 42);

    // Gerar tabela no PDF a partir dos dados da tabela HTML
    doc.autoTable({
        html: '#tabela-pdf',
        startY: 50,
        theme: 'grid',
        headStyles: { fillColor: [30, 58, 138] }, // Cor azul marinho
        columns: [
            { header: 'PRODUTO', dataKey: 'produto' },
            { header: 'PATRIMÔNIO', dataKey: 'serie' },
            { header: 'ESTADO', dataKey: 'estado' },
            { header: 'NOTA FISCAL', dataKey: 'nf' }
        ]
    });

    // Rodapé para Assinatura
    const finalY = doc.lastAutoTable.finalY + 30;
    doc.line(14, finalY, 80, finalY);
    doc.text("Assinatura do Responsável", 14, finalY + 5);

    doc.save(`Inventario_${nomeSetor.replace(/ /g, '_')}.pdf`);
}

async function telaPatrimonioRegistarItem() {
    const modal = document.createElement('div');
    modal.id = 'modal-registo-item';
    modal.className = 'alerta-vidro-overlay';

    try {
        // Carregamos os dados necessários em paralelo
        const [resProds, resSetores] = await Promise.all([
            fetch(`${API_URL}/produtos?tipo=PATRIMONIO`, { headers: { 'Authorization': `Bearer ${TOKEN}` } }),
            fetch(`${API_URL}/patrimonio/setores/meus`, { headers: { 'Authorization': `Bearer ${TOKEN}` } })
        ]);

        const produtos = await resProds.json();
        const setores = await resSetores.json();

        modal.innerHTML = `
            <div class="painel-vidro" style="width: 500px; padding: 30px; border-radius: 20px;">
                <h2 style="color:white; margin-top:0; display:flex; align-items:center; gap:10px;">
                    <span>➕</span> NOVO ITEM DE PATRIMÔNIO
                </h2>
                
                <div style="display:flex; flex-direction:column; gap:15px; margin-top:20px;">
                    
                    <div>
                        <label style="color:white; font-size:0.8rem; opacity:0.7;">PRODUTO (CATÁLOGO)</label>
                        <select id="reg-pat-produto" style="width:100%; padding:12px; border-radius:10px; background:rgba(255,255,255,0.1); color:white; border:1px solid rgba(255,255,255,0.2);">
                            <option value="" style="color:black;">Selecione o produto...</option>
                            ${produtos.map(p => `<option value="${p.id}" style="color:black;">${p.nome}</option>`).join('')}
                        </select>
                    </div>

                    <div>
                        <label style="color:white; font-size:0.8rem; opacity:0.7;">ALOCAR NO SETOR / SALA</label>
                        <select id="reg-pat-setor" style="width:100%; padding:12px; border-radius:10px; background:rgba(255,255,255,0.1); color:white; border:1px solid rgba(255,255,255,0.2);">
                            <option value="" style="color:black;">Selecione o local físico...</option>
                            ${setores.map(s => `<option value="${s.id}" style="color:black;">${s.nome}</option>`).join('')}
                        </select>
                    </div>

                    <div>
                        <label style="color:white; font-size:0.8rem; opacity:0.7;">Nº PATRIMÔNIO</label>
                        <input type="text" id="reg-pat-serie" placeholder="Ex: ABC-12345" 
                            style="width:100%; padding:12px; border-radius:10px; background:rgba(255,255,255,0.1); color:white; border:1px solid rgba(255,255,255,0.2);">
                    </div>

                    <div>
                        <label style="color:white; font-size:0.8rem; opacity:0.7;">NOTA FISCAL (OPCIONAL)</label>
                        <input type="text" id="reg-pat-nf" placeholder="Nº da NF" 
                            style="width:100%; padding:12px; border-radius:10px; background:rgba(255,255,255,0.1); color:white; border:1px solid rgba(255,255,255,0.2);">
                    </div>

                    <div style="display:flex; gap:10px; margin-top:10px;">
                        <button onclick="document.getElementById('modal-registo-item').remove()" 
                            style="flex:1; padding:12px; background:transparent; color:white; border:1px solid rgba(255,255,255,0.3); border-radius:12px; cursor:pointer;">
                            CANCELAR
                        </button>
                        <button onclick="salvarNovoPatrimonio()" 
                            style="flex:2; padding:12px; background:#3b82f6; color:white; border:none; border-radius:12px; cursor:pointer; font-weight:bold; box-shadow: 0 4px 15px rgba(59,130,246,0.3);">
                            CONFIRMAR REGISTRO
                        </button>
                    </div>
                </div>
            </div>
        `;

        document.body.appendChild(modal);

    } catch (err) {
        console.error(err);
        notificar("Erro ao carregar dados para registo.");
    }

    // Função interna para processar o envio
    window.salvarNovoPatrimonio = async () => {
        const payload = {
            produto_id: document.getElementById('reg-pat-produto').value,
            setor_id: document.getElementById('reg-pat-setor').value,
            numero_serie: document.getElementById('reg-pat-serie').value,
            nota_fiscal: document.getElementById('reg-pat-nf').value
        };

        if (!payload.produto_id || !payload.setor_id) {
            return notificar("Por favor, selecione o produto e o setor.");
        }

        const res = await fetch(`${API_URL}/patrimonio/itens`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${TOKEN}` },
            body: JSON.stringify(payload)
        });

        if (res.ok) {
            notificar("Item registado com sucesso!", "sucesso");
            document.getElementById('modal-registo-item').remove();
        } else {
            const erro = await res.json();
            notificar("Erro: " + erro.error);
        }
    };
}

async function telaGerenciarSetores() {
    const modal = document.createElement('div');
    modal.id = 'modal-setores';
    modal.className = 'alerta-vidro-overlay';
    
    modal.innerHTML = `
        <div class="painel-vidro" style="width: 800px; height: 500px; display: flex; gap: 20px; padding: 25px;">
            <div style="flex: 1; border-right: 1px solid rgba(255,255,255,0.1); padding-right: 20px;">
                <h3 style="color:white; margin-top:0;">📂 NOVO SETOR</h3>
                <input type="text" id="nome-setor" placeholder="Ex: SALA DE AULA 01" 
                    style="width:100%; padding:12px; border-radius:10px; background:rgba(255,255,255,0.1); color:white; border:1px solid rgba(255,255,255,0.2);">
                <button onclick="salvarSetor()" style="width:100%; margin-top:15px; padding:12px; background:#10b981; color:white; border:none; border-radius:10px; cursor:pointer; font-weight:bold;">
                    SALVAR SETOR
                </button>
                <button onclick="document.getElementById('modal-setores').remove()" style="width:100%; margin-top:10px; background:transparent; color:white; border:1px solid rgba(255,255,255,0.3); padding:8px; border-radius:10px; cursor:pointer;">
                    CANCELAR
                </button>
            </div>

            <div style="flex: 1; display:flex; flex-direction:column;">
                <h3 style="color:white; margin-top:0;">📋 SETORES CADASTRADOS</h3>
                <div id="lista-setores-escola" style="flex:1; overflow-y:auto; max-height:300px; background:rgba(0,0,0,0.2); border-radius:10px; padding:10px;">
                    </div>
            </div>
        </div>
    `;

    document.body.appendChild(modal);
    await atualizarListaSetores();

    window.salvarSetor = async () => {
        const nome = document.getElementById('nome-setor').value;
        if (!nome) return notificar("Digite o nome do setor.");

        const res = await fetch(`${API_URL}/patrimonio/setores`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${TOKEN}` },
            body: JSON.stringify({ nome })
        });

        if (res.ok) {
            document.getElementById('nome-setor').value = '';
            // Chama a função de atualização para refletir a mudança no modal
            await atualizarListaSetores(); 
        } else {
            const erro = await res.json();
            notificar(erro.error);
        }
    };
}

