async function carregarListaLocaisGlobal() {
    try {
        const res = await fetch(`${API_URL}/patrimonio/global/locais`, {
            headers: { 'Authorization': `Bearer ${TOKEN}` }
        });
        const locais = await res.json();
        const container = document.getElementById('col-locais');

        container.innerHTML = locais.map(l => `
            <div class="item-setor-clicavel item-global" onclick="selecionarLocalGlobal(${l.id}, '${l.nome}')" 
                 style="padding:15px; margin: 10px 0; background:rgba(255,255,255,0.05); border-radius:10px; cursor:pointer; text-align:center; transition: 0.3s;">
                ${l.nome}
            </div>
        `).join('');
    } catch (err) {
        console.error("Erro locais:", err);
    }
}

window.selecionarLocalGlobal = async function(id, nome) {
    window.localSelecionadoId = id;
    window.localSelecionadoNome = nome;

    // Reset de visual e colunas
    document.querySelectorAll('.item-global').forEach(el => el.style.background = 'rgba(255,255,255,0.05)');
    event.currentTarget.style.background = 'rgba(59, 130, 246, 0.3)';
    
    document.getElementById('container-setores').style.display = 'flex';
    document.getElementById('container-bens').style.display = 'none';
    document.getElementById('acoes-global').style.display = 'flex';
    document.getElementById('txt-local-selecionado').innerText = `📍 ${nome}`;
    document.getElementById('col-setores').innerHTML = '<div class="spinner"></div>';

    try {
        const res = await fetch(`${API_URL}/patrimonio/global/setores/${id}`, {
            headers: { 'Authorization': `Bearer ${TOKEN}` }
        });
        const setores = await res.json();
        
        document.getElementById('col-setores').innerHTML = setores.map(s => `
            <div class="item-setor-clicavel item-setor-global" onclick="selecionarSetorGlobal(${s.id}, '${s.nome}')" 
                 style="padding:12px; margin-bottom:8px; background:rgba(255,255,255,0.05); border-radius:8px; cursor:pointer;">
                🔹 ${s.nome}
            </div>
        `).join('') || '<p style="color:gray; font-size:0.8rem;">Nenhum setor.</p>';
    } catch (err) {
        console.error(err);
    }
};

window.selecionarSetorGlobal = async function(setor_id, nome_setor) {
    // Reset visual dos setores
    document.querySelectorAll('.item-setor-global').forEach(el => el.style.background = 'rgba(255,255,255,0.05)');
    if (event && event.currentTarget) event.currentTarget.style.background = 'rgba(52, 211, 153, 0.3)';

    document.getElementById('container-bens').style.display = 'flex';
    document.getElementById('txt-setor-selecionado').innerText = `📋 ITENS EM: ${nome_setor}`;
    const colBens = document.getElementById('col-bens');
    colBens.innerHTML = '<div class="spinner"></div>';

    // Desativa o botão de auditoria até uma nova seleção
    const btnAuditoria = document.getElementById('btn-editar-auditoria');
    if (btnAuditoria) {
        btnAuditoria.disabled = true;
        btnAuditoria.style.opacity = '0.3';
        btnAuditoria.style.cursor = 'not-allowed';
    }

    try {
        const res = await fetch(`${API_URL}/patrimonio/global/bens/${setor_id}`, {
            headers: { 'Authorization': `Bearer ${TOKEN}` }
        });
        const bens = await res.json();
        
        // GUARDA A LISTA NA MEMÓRIA (Evita erros de aspas/caracteres no HTML)
        window.listaBensAtual = bens;

        colBens.innerHTML = bens.map((b, index) => `
            <div class="linha-patrimonio item-bem-auditoria" 
                 id="bem-row-${index}"
                 onclick="selecionarBemParaAuditoria(${index})" 
                 style="padding:15px; border-bottom:1px solid rgba(255,255,255,0.05); cursor:pointer; display:flex; justify-content:space-between; transition: 0.2s; align-items:center;">
                
                <div style="text-align:left;">
                    <strong style="display:block; color:white; font-size:0.95rem;">${b.nome_produto}</strong>
                    <span style="opacity:0.5; font-size:0.75rem;">SÉRIE: ${b.numero_serie || 'S/N'}</span>
                </div>

                <div style="text-align:right; display:flex; flex-direction:column; align-items:flex-end;">
                    <span id="label-patrimonio-${index}" style="background:rgba(96, 165, 250, 0.1); color:#60a5fa; padding:4px 10px; border-radius:6px; font-size:0.75rem; font-weight:bold; border:1px solid rgba(96, 165, 250, 0.2);">
                        ${b.patrimonio || 'S/ ETIQUETA'}
                    </span>
                    <small style="opacity:0.3; font-size:0.6rem; margin-top:5px;">ID: #${b.id}</small>
                </div>
            </div>
        `).join('') || '<p style="color:gray; text-align:center; margin-top:20px;">Setor vazio.</p>';

    } catch (err) {
        console.error(err);
        colBens.innerHTML = '<p style="color:#ef4444; padding:20px;">Erro ao carregar bens.</p>';
    }
};

window.selecionarBemParaAuditoria = function(index) {
    // Busca os dados direto da memória pelo índice
    const dadosBem = window.listaBensAtual[index];
    window.bemSelecionadoIndex = index;
    window.bemSelecionadoDados = dadosBem;

    // Destaque visual da linha selecionada
    document.querySelectorAll('.item-bem-auditoria').forEach(el => {
        el.style.background = 'transparent';
        el.style.borderLeft = 'none';
    });

    const row = document.getElementById(`bem-row-${index}`);
    if (row) {
        row.style.background = 'rgba(59, 130, 246, 0.2)';
        row.style.borderLeft = '4px solid #60a5fa';
    }

    // Ativa o botão azul "IDENTIFICAR PATRIMÔNIO"
    const btn = document.getElementById('btn-editar-auditoria');
    if (btn) {
        btn.disabled = false;
        btn.style.opacity = '1';
        btn.style.cursor = 'pointer';
        btn.style.background = '#3b82f6'; 
        btn.style.boxShadow = '0 0 15px rgba(59, 130, 246, 0.4)';
    }
};

function renderizarBensGlobal(bens) {
    const container = document.getElementById('col-bens');
    container.innerHTML = bens.map(b => {
        // Monta o texto do Hover com todos os campos
        const detalhes = `
            Nº SÉRIE: ${b.numero_serie || 'N/A'}
            PATRIMÔNIO: ${b.documento_id || 'N/A'}
            NF / CE: ${b.nota_fiscal || 'N/A'}
            ESTADO: ${b.estado}
            CADASTRO: ${new Date(b.data_atualizacao).toLocaleDateString()}
            STATUS: ${b.status}
        `.trim();

        return `
            <div class="linha-patrimonio" title="${detalhes}" 
                 style="padding:15px; border-bottom:1px solid rgba(255,255,255,0.1); cursor:help; display:flex; justify-content:space-between;">
                <span><strong>${b.nome_produto}</strong></span>
                <span style="opacity:0.6; font-size:0.8rem;">${b.numero_serie || 'S/N'}</span>
            </div>
        `;
    }).join('');
}

async function exportarGlobalExcel() {
    const localId = window.localSelecionadoId;
    const nomeLocal = window.localSelecionadoNome;

    const res = await fetch(`${API_URL}/patrimonio/global/relatorio/${localId}`, {
        headers: { 'Authorization': `Bearer ${TOKEN}` }
    });
    const dados = await res.json();

    // Mapeamento para garantir a inclusão do patrimônio e definir a ordem das colunas
    const dadosFormatados = dados.map(d => ({
        'SETOR': d.setor,
        'PRODUTO': d.produto,
        'Nº PATRIMÔNIO': d.numero_serie || '---',
        'Nº RGP': d.patrimonio || '---',
        'ESTADO': d.estado,
        'NF / CE': d.nota_fiscal || '---',
        'DATA CADASTRO': d.data_atualizacao ? new Date(d.data_atualizacao).toLocaleDateString('pt-BR') : '---'
    }));

    const ws = XLSX.utils.json_to_sheet(dadosFormatados);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Patrimonio");

    XLSX.writeFile(wb, `Relatorio_Patrimonio_${nomeLocal.replace(/ /g, '_')}.xlsx`);
}

async function exportarGlobalPDF() {
    const localId = window.localSelecionadoId;
    const nomeLocal = window.localSelecionadoNome;

    const res = await fetch(`${API_URL}/patrimonio/global/relatorio/${localId}`, {
        headers: { 'Authorization': `Bearer ${TOKEN}` }
    });
    const dados = await res.json();

    const { jsPDF } = window.jspdf;
    // 'l' para landscape (paisagem) ajuda a acomodar a nova coluna em telas ou impressões A4
    const doc = new jsPDF('l', 'mm', 'a4'); 

    doc.setFontSize(16);
    doc.text(`RELATÓRIO DE INVENTÁRIO - ${nomeLocal}`, 148, 15, { align: "center" });

    doc.autoTable({
        head: [['SETOR', 'PRODUTO', 'PATRIMÔNIO', 'RGP', 'ESTADO', 'NF / CE']],
        body: dados.map(d => [
            d.setor, 
            d.produto, 
            d.numero_serie || '---', 
            d.patrimonio || '---', 
            d.estado, 
            d.nota_fiscal || '---'
        ]),
        startY: 25,
        theme: 'grid',
        headStyles: { fillColor: [31, 58, 138] },
        styles: { fontSize: 9 }, // Tamanho de fonte ajustado para a nova estrutura
        columnStyles: {
            3: { fontStyle: 'bold', textColor: [31, 58, 138] } // Destaca a coluna do Patrimônio
        }
    });

    doc.save(`Inventario_${nomeLocal}.pdf`);
}

async function salvarAlteracaoEstado(id) {
    const novoEstado = document.getElementById('novo-estado-bem').value;

    try {
        const res = await fetch(`${API_URL}/patrimonio/item/${id}/estado`, {
            method: 'PATCH',
            headers: { 
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${TOKEN}` 
            },
            body: JSON.stringify({ estado: novoEstado })
        });

        if (res.ok) {
            document.getElementById('modal-editar-estado').remove();
            // Atualiza a lista atual para refletir a mudança
            if (typeof carregarItensPorSetor === 'function') {
                const setorId = document.querySelector('.item-setor-clicavel.setor-ativo')?.getAttribute('data-id');
                const nomeSetor = document.getElementById('nome-setor-titulo').innerText.replace('ITENS EM: ', '');
                await carregarItensPorSetor(setorId, nomeSetor);
            }
            notificar("Estado atualizado com sucesso!");
        }
    } catch (err) {
        notificar("Erro ao salvar alteração.");
    }
}

window.prepararEdicaoItem = () => {
    if (window.itemSelecionadoId) {
        telaEditarItemPatrimonio(window.itemSelecionadoId);
    } else {
        notificar("Por favor, selecione um item na lista primeiro clicando sobre ele.");
    }
};

function alertaSucessoPatrimonio() {
    const alerta = document.createElement('div');
    alerta.style.cssText = `
        position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%);
        background: rgba(34, 197, 94, 0.95); color: white; padding: 60px 100px;
        border-radius: 30px; font-size: 2.2rem; font-weight: 900; z-index: 10001;
        box-shadow: 0 20px 50px rgba(0,0,0,0.5); backdrop-filter: blur(15px);
        text-align: center; border: 2px solid rgba(255,255,255,0.2); pointer-events: none;
    `;
    alerta.innerHTML = `✅ BEM REGISTRADO!`;
    document.body.appendChild(alerta);

    setTimeout(() => {
        alerta.style.opacity = '0';
        alerta.style.transition = 'opacity 0.5s ease';
        setTimeout(() => alerta.remove(), 500);
    }, 1000);
}

function habilitarAcoesTransferencia(id, setorIdAtual) {
    window.itemSelecionadoId = id;
    window.setorIdOrigem = setorIdAtual;

    const btnInterno = document.getElementById('btn-transferir-interno');
    const btnExterno = document.getElementById('btn-transferir-externo');

    if (btnInterno && btnExterno) {
        [btnInterno, btnExterno].forEach(btn => {
            btn.disabled = false;
            btn.classList.add('active');
        });
    }
}

function selecionarItemParaTransferencia(elemento, id, setorIdAtual) {
    // 1. Remove destaque visual de qualquer outra linha selecionada anteriormente
    document.querySelectorAll('.linha-selecionada').forEach(el => el.classList.remove('linha-selecionada'));
    
    // 2. Marca a linha atual (a que você clicou) com a cor de destaque
    elemento.classList.add('linha-selecionada');
    
    // 3. Salva os IDs na memória global para que as outras funções saibam QUEM e de ONDE estamos movendo
    window.itemSelecionadoId = id;
    window.setorIdOrigem = setorIdAtual;

    // 4. Localiza e "acende" os botões de transferência na extrema direita
    const btnInterno = document.getElementById('btn-transferir-interno');
    const btnExterno = document.getElementById('btn-transferir-externo');
    
    if (btnInterno) {
        btnInterno.disabled = false;
        btnInterno.classList.add('ativo'); // Ativa o gradiente azul definido no CSS
    }
    if (btnExterno) {
        btnExterno.disabled = false;
        btnExterno.classList.add('ativo'); // Ativa o gradiente azul definido no CSS
    }
}

async function abrirModalTransferenciaInterna() {
    const id = window.itemSelecionadoId;
    const setorAtual = window.setorIdOrigem;

    // Busca setores para o local atual
    const res = await fetch(`${API_URL}/patrimonio/setores/meus`, {
        headers: { 'Authorization': `Bearer ${TOKEN}` }
    });
    const setores = await res.json();

    // Filtra para não mostrar o setor onde o bem já está
    const outrosSetores = setores.filter(s => s.id !== setorAtual);

    const modal = document.createElement('div');
    modal.id = 'modal-transferencia-interna';
    modal.className = 'alerta-vidro-overlay';
    modal.style.zIndex = "20000";

    modal.innerHTML = `
        <div class="painel-vidro" style="width: 450px; padding: 35px; text-align: center; border: 1px solid rgba(59, 130, 246, 0.5);">
            <h3 style="color:white; margin-top:0;">TRANSFERIR BEM</h3>
            <p style="color:#94a3b8; font-size:0.9rem; margin-bottom:25px;">Selecione o setor de destino para o item selecionado.</p>
            
            <select id="select-destino-interno" class="input-vidro" style="width:100%; margin-bottom:30px; background:#0f172a; color:white;" onchange="document.getElementById('btn-confirmar-transferencia').disabled = false">
                <option value="" disabled selected>Escolha o novo setor...</option>
                ${outrosSetores.map(s => `<option value="${s.id}">${s.nome}</option>`).join('')}
            </select>

            <div style="display:flex; gap:15px;">
                <button onclick="cancelarTransferenciaInterna()" class="btn-sair-vidro" style="flex:1;">CANCELAR</button>
                <button id="btn-confirmar-transferencia" disabled onclick="executarTransferenciaInterna()" style="flex:1; background:#10b981; color:white; border:none; border-radius:10px; font-weight:bold; cursor:pointer;">
                    CONFIRMAR
                </button>
            </div>
        </div>
    `;
    document.body.appendChild(modal);
}

function cancelarTransferenciaInterna() {
    const modal = document.getElementById('modal-transferencia-interna');
    if (modal) modal.remove();
    
    // Desativa seleção e botões conforme regra
    document.querySelectorAll('.linha-selecionada').forEach(el => el.classList.remove('linha-selecionada'));
    const btnInterno = document.getElementById('btn-transferir-interno');
    const btnExterno = document.getElementById('btn-transferir-externo');
    if (btnInterno) { btnInterno.disabled = true; btnInterno.classList.remove('ativo'); }
    if (btnExterno) { btnExterno.disabled = true; btnExterno.classList.remove('ativo'); }
}

function fecharModalTransferencia() {
    const modal = document.getElementById('modal-transferencia-interna');
    if (modal) modal.remove();
    // Deseleciona visualmente mas mantém no registro (lógica de UI)
}

async function executarTransferenciaInterna() {
    const novoSetorId = document.getElementById('select-destino-interno').value;
    const patrimonioId = window.itemSelecionadoId;

    try {
        const res = await fetch(`${API_URL}/patrimonio/transferir/interno`, {
            method: 'PATCH',
            headers: { 
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${TOKEN}` 
            },
            body: JSON.stringify({ patrimonio_id: patrimonioId, novo_setor_id: novoSetorId })
        });

        if (res.ok) {
            // 1. Fecha o modal primeiro para limpar a tela
            const modal = document.getElementById('modal-transferencia-interna');
            if (modal) modal.remove();

            // 2. Alerta de sucesso
            if (typeof alertaSucessoPatrimonio === 'function') alertaSucessoPatrimonio();
            
            // 3. ATUALIZAÇÃO DA LISTA (Onde o erro acontecia)
            // Em vez de travar tentando ler o innerText, usamos um fallback
            const elTitulo = document.getElementById('nome-setor-titulo');
            const nomeSetor = elTitulo ? elTitulo.innerText : "Setor";

            // 4. Recarrega o setor de ORIGEM. 
            // Como o banco já mudou o setor do item, ele vai sumir da lista automaticamente aqui.
            await carregarItensPorSetor(window.setorIdOrigem, nomeSetor);

            // 5. Reseta os botões de ação do topo
            document.getElementById('btn-transferir-interno').disabled = true;
            document.getElementById('btn-transferir-interno').classList.remove('ativo');
            document.getElementById('btn-transferir-externo').disabled = true;
            document.getElementById('btn-transferir-externo').classList.remove('ativo');
        }
    } catch (err) {
        console.error("Erro ao processar atualização da lista:", err);
    }
}

async function confirmarTransferenciaInterna() {
    const selectDestino = document.getElementById('select-destino');
    if (!selectDestino) return;
    
    const novoSetorId = selectDestino.value;
    
    try {
        const res = await fetch(`${API_URL}/patrimonio/transferir/interno`, {
            method: 'PATCH',
            headers: { 
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${TOKEN}` 
            },
            body: JSON.stringify({ 
                patrimonio_id: window.itemSelecionadoId, 
                novo_setor_id: novoSetorId 
            })
        });

        if (res.ok) {
            // 1. Alerta de Sucesso
            if (typeof alertaSucessoPatrimonio === 'function') alertaSucessoPatrimonio();
            
            // 2. Fecha o modal
            const modal = document.getElementById('modal-transferencia-interna');
            if (modal) modal.remove();
            
            // 3. ATUALIZAÇÃO DA LISTA (O PONTO CRÍTICO)
            // Verificamos se o elemento do título existe para evitar o erro de 'null'
            const elementoTitulo = document.getElementById('nome-setor-titulo');
            const nomeSetor = elementoTitulo ? elementoTitulo.innerText : 'Setor';

            // 4. Recarrega os itens do setor de origem (onde o bem acabou de sair)
            if (window.setorIdOrigem) {
                // Força a atualização da tabela para que o bem transferido desapareça da vista
                await carregarItensPorSetor(window.setorIdOrigem, nomeSetor);
            }
        }
    } catch (err) {
        console.error("Erro ao atualizar lista após transferência:", err);
    }
}

async function verificarAlertasPatrimonio() {
    const badge = document.getElementById('badge-infra-count');
    if (!badge) return;

    try {
        // Buscamos os pedidos pendentes
        const res = await fetch(`${API_URL}/infra/pendentes`, {
            headers: { 'Authorization': `Bearer ${TOKEN}` }
        });
        const dados = await res.json();

        // Filtra conforme a sua regra de negócio
        const pendentesInfra = dados.filter(p => 
            p.tipo_pedido === 'INFRA_PATRIMONIO' && 
            p.status === 'AGUARDANDO_AUTORIZACAO'
        );

        const total = pendentesInfra.length;

        if (total > 0) {
            badge.innerText = total;
            badge.style.display = 'flex'; // Exibe e começa a pulsar via CSS
        } else {
            badge.style.display = 'none'; // Esconde se for zero
        }
    } catch (err) {
        console.error("Erro ao verificar alertas de infra:", err);
    }
}

